mapper.select:
select  from policy_source where deleted = 0
and project_id = #{projectId}
and project_id in #{pid}
and (name like concat('%', #{keyword}, '%') or url like concat('%', #{keyword}, '%'))
and status = #{status}
order by updated_at desc, id desc

select  from policy_crawl_task where deleted = 0
and project_id = #{projectId}
and project_id in #{pid}
and source_id = #{sourceId}
and status = #{status}
order by created_at desc, task_id desc

select  from policy_article where deleted = 0
and project_id = #{projectId}
and project_id in #{pid}
and source_id = #{sourceId}
and (title like concat('%', #{keyword}, '%') or summary like concat('%', #{keyword}, '%') or content like concat('%', #{keyword}, '%'))
and index_status = #{indexStatus}
and publish_date >= #{publishDateFrom}
and publish_date <= #{publishDateTo}
order by publish_date desc, updated_at desc, id desc
